[['APP_NAME'], ['APP_URL'], ['DB_HOST', 'DB_NAME', 'DB_USER', 'DB_PASS'], "<?php\n\n// Application configuration\n\ndefine('APP_NAME', 'Hospital Management System');\ndefine('APP_URL', 'http://localhost/medical');\n\ndefine('DB_HOST', 'localhost');\ndefine('DB_NAME', 'hospital_db');\ndefine('DB_USER', 'root');\ndefine('DB_PASS', '');\n\ndefine('APP_PATH', __DIR__ . '/../');\ndefine('PUBLIC_PATH', __DIR__ . '/../../public');\n\ndefine('ASSETS_URL', APP_URL . '/public');\n\ndefine('DATE_FORMAT', 'Y-m-d');\ndefine('TIME_FORMAT', 'H:i:s');\n\ndefine('DEFAULT_TIMEZONE', 'UTC');\n\ndefine('SESSION_LIFETIME', 3600);\n\ndefine('MAX_UPLOAD_SIZE', 5 * 1024 * 1024); // 5MB\n\ndefine('ALLOWED_FILE_TYPES', ['jpg', 'jpeg', 'png', 'pdf']);\n\n// Status constants\ndefine('APPOINTMENT_STATUS_PENDING', 'pending');\ndefine('APPOINTMENT_STATUS_CONFIRMED', 'confirmed');\ndefine('APPOINTMENT_STATUS_CANCELLED', 'cancelled');\ndefine('APPOINTMENT_STATUS_COMPLETED', 'completed');\n\n// Gender constants\ndefine('GENDER_MALE', 'male');\ndefine('GENDER_FEMALE', 'female');\ndefine('GENDER_OTHER', 'other');\n\n// Role constants\ndefine('ROLE_ADMIN', 'admin');\ndefine('ROLE_DOCTOR', 'doctor');\ndefine('ROLE_NURSE', 'nurse');\ndefine('ROLE_PATIENT', 'patient');\n\n// Pagination\ndefine('ITEMS_PER_PAGE', 10);\n\n// Security settings\ndefine('PASSWORD_MIN_LENGTH', 8);\n\ndefine('TOKEN_EXPIRY', 3600); // 1 hour\n\nreturn [\n    'app' => [\n        'name' => APP_NAME,\n        'url' => APP_URL,\n    ],\n    'database' => [\n        'host' => DB_HOST,\n        'name' => DB_NAME,\n        'user' => DB_USER,\n        'pass' => DB_PASS,\n    ],\n    'security' => [\n        'min_password_length' => PASSWORD_MIN_LENGTH,\n        'token_expiry' => TOKEN_EXPIRY,\n    ],\n    'pagination' => [\n        'items_per_page' => ITEMS_PER_PAGE,\n    ],\n];"]